#!/usr/bin/env node
/**
 * ReviewLens AI — automated demo recorder
 *
 * Records a walkthrough of all 3 above-and-beyond features:
 *   1. Proactive Insight Brief
 *   2. Quick-Start Prompts
 *   3. Contextual Follow-Up Chips
 *
 * Usage:
 *   node scripts/record-demo.js
 *
 * Env vars (all optional):
 *   BASE_URL            — default: https://reviewlens-ai-f6lj.onrender.com
 *   TRUSTPILOT_URL      — default: https://www.trustpilot.com/review/notion.so
 *   REVIEW_CAP          — default: 15  (keep small for fast demo)
 *   EXISTING_SESSION_ID — skip ingestion, jump straight to this session
 *   CHROME_PATH         — override Chrome executable path
 *
 * Output: demo-out/demo.mp4  (via ffmpeg from demo-out/demo.webm)
 */

const { chromium } = require('playwright-core');
const { execSync, spawnSync } = require('child_process');
const path = require('path');
const fs = require('fs');

const BASE_URL = process.env.BASE_URL || 'https://reviewlens-ai-f6lj.onrender.com';
const TRUSTPILOT_URL = process.env.TRUSTPILOT_URL || 'https://www.trustpilot.com/review/notion.so';
const REVIEW_CAP = process.env.REVIEW_CAP || '15';
const EXISTING_SESSION_ID = process.env.EXISTING_SESSION_ID || '';
const CHROME_PATH =
  process.env.CHROME_PATH ||
  '/Applications/Google Chrome.app/Contents/MacOS/Google Chrome';

const OUT_DIR = path.join(__dirname, '..', 'demo-out');
const WEBM_PATH = path.join(OUT_DIR, 'demo.webm');
const MP4_PATH = path.join(OUT_DIR, 'demo.mp4');

const pause = (ms) => new Promise((r) => setTimeout(r, ms));

async function slowType(locator, text, delayMs = 60) {
  await locator.click();
  for (const ch of text) {
    await locator.type(ch);
    await pause(delayMs);
  }
}

async function waitForInsightBrief(page) {
  // Wait until the "AI Insights" card is visible and stops showing "Analyzing"
  await page.waitForSelector('text=AI Insights', { timeout: 60_000 });
  // Wait for the loading text to disappear (analysis complete)
  try {
    await page.waitForSelector('text=Analyzing reviews…', { state: 'detached', timeout: 90_000 });
  } catch {
    // already gone or never appeared — fine
  }
}

async function waitForFollowUpChips(page) {
  // Wait for the loading skeleton to disappear and chips to appear
  // Chips are small border-violet buttons that appear after assistant message
  try {
    await page.waitForSelector('.animate-pulse', { state: 'detached', timeout: 30_000 });
  } catch { /* ignore */ }
  await pause(1000);
}

(async () => {
  console.log('🎬  ReviewLens AI — Demo Recorder');
  console.log(`    BASE_URL: ${BASE_URL}`);
  console.log(`    Output:   ${MP4_PATH}`);
  console.log('');

  if (!fs.existsSync(CHROME_PATH)) {
    console.error(`Chrome not found at: ${CHROME_PATH}`);
    console.error('Set CHROME_PATH env var to your Chrome/Chromium executable.');
    process.exit(1);
  }

  // Clean up old webm
  if (fs.existsSync(WEBM_PATH)) fs.unlinkSync(WEBM_PATH);

  const browser = await chromium.launch({
    executablePath: CHROME_PATH,
    headless: false,  // visible window looks better for a demo
    slowMo: 0,
    args: ['--window-size=1280,800'],
  });

  const context = await browser.newContext({
    viewport: { width: 1280, height: 800 },
    recordVideo: {
      dir: OUT_DIR,
      size: { width: 1280, height: 800 },
    },
  });

  const page = await context.newPage();

  // ─────────────────────────────────────────────────────────
  // SCENE 1: Home page
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 1 — Home page');
  await page.goto(BASE_URL, { waitUntil: 'networkidle' });
  await pause(2000);

  let sessionId = EXISTING_SESSION_ID;

  if (!sessionId) {
    // ─────────────────────────────────────────────────────────
    // SCENE 2: Ingest a Trustpilot URL
    // ─────────────────────────────────────────────────────────
    console.log('📍  Scene 2 — Ingest Trustpilot URL');

    // Navigate to new session form (home page IS the form)
    const urlInput = page.locator('input[placeholder*="trustpilot"]').first();
    await urlInput.scrollIntoViewIfNeeded();
    await pause(800);
    await slowType(urlInput, TRUSTPILOT_URL, 40);
    await pause(600);

    // Set cap
    const capInput = page.locator('input[type="number"]').first();
    await capInput.triple_click?.() || await capInput.click({ clickCount: 3 });
    await capInput.fill(REVIEW_CAP);
    await pause(500);

    // Click ingest
    const ingestBtn = page.locator('button:has-text("Ingest Reviews")');
    await ingestBtn.click();
    await pause(1000);

    // ─────────────────────────────────────────────────────────
    // SCENE 3: Ingestion progress
    // ─────────────────────────────────────────────────────────
    console.log('📍  Scene 3 — Ingestion in progress…');
    // Watch the step list and page indicators animate
    await pause(4000);

    // Wait for redirect to session page (up to 3 minutes for scraping + save)
    console.log('    Waiting for redirect to session page…');
    await page.waitForURL((url) => url.pathname.startsWith('/session/'), {
      timeout: 180_000,
    });

    sessionId = page.url().split('/session/')[1];
    console.log(`    Session ID: ${sessionId}`);
  } else {
    // Jump directly to existing session
    console.log(`📍  Skipping ingestion — using session ${sessionId}`);
    await page.goto(`${BASE_URL}/session/${sessionId}`, { waitUntil: 'networkidle' });
  }

  await pause(2000);

  // ─────────────────────────────────────────────────────────
  // SCENE 4: Session page loads — Insight Brief animates in
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 4 — Session page + Insight Brief');
  await page.waitForURL((url) => url.pathname.startsWith('/session/'), { timeout: 10_000 });
  await pause(1500);

  // Scroll to chat panel
  const insightCard = page.locator('text=AI Insights').first();
  await insightCard.scrollIntoViewIfNeeded();
  await pause(1000);

  // Wait for analysis to finish
  console.log('    Waiting for AI Insights analysis…');
  await waitForInsightBrief(page);
  await pause(2000);

  // ─────────────────────────────────────────────────────────
  // SCENE 5: Expand Insight Brief
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 5 — Expand Insight Brief');
  await insightCard.click();
  await pause(3000);  // linger on the expanded themes

  // ─────────────────────────────────────────────────────────
  // SCENE 6: Show Quick-Start Prompts (only if empty chat)
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 6 — Quick-Start Prompts');
  const quickStartBtn = page.locator('button:has-text("top 3 customer complaints")').first();
  const hasQuickStart = await quickStartBtn.isVisible().catch(() => false);
  if (hasQuickStart) {
    await quickStartBtn.scrollIntoViewIfNeeded();
    await pause(2000);  // linger to show the buttons
    await quickStartBtn.click();
  } else {
    // Chat has history — type manually
    console.log('    Chat already has history, typing manually…');
    const input = page.locator('input[placeholder*="Ask about"]');
    await input.click();
    await slowType(input, 'What are the top 3 customer complaints?', 50);
    await page.keyboard.press('Enter');
  }

  // ─────────────────────────────────────────────────────────
  // SCENE 7: Wait for assistant response
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 7 — Waiting for assistant response…');
  // Wait for Thinking… to appear then disappear
  try {
    await page.waitForSelector('text=Thinking…', { timeout: 10_000 });
  } catch { /* already gone */ }
  await page.waitForSelector('text=Thinking…', { state: 'detached', timeout: 60_000 });
  await pause(1500);

  // Scroll down to see full response
  await page.evaluate(() => window.scrollTo(0, document.body.scrollHeight));
  await pause(2000);

  // ─────────────────────────────────────────────────────────
  // SCENE 8: Follow-Up Chips appear
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 8 — Follow-Up Chips');
  console.log('    Waiting for follow-up chips…');
  await waitForFollowUpChips(page);

  // Find and highlight a follow-up chip
  const chip = page.locator('button.rounded-full.border-violet-200').first();
  const chipVisible = await chip.isVisible().catch(() => false);
  if (chipVisible) {
    await chip.scrollIntoViewIfNeeded();
    await pause(2000);  // linger so chips are clearly visible

    // Click the chip
    console.log('    Clicking follow-up chip…');
    await chip.click();
    await pause(1000);

    // Wait for second response
    try {
      await page.waitForSelector('text=Thinking…', { timeout: 8_000 });
    } catch { /* already gone */ }
    await page.waitForSelector('text=Thinking…', { state: 'detached', timeout: 60_000 });
    await pause(2000);
  } else {
    console.log('    No follow-up chips visible — skipping chip scene');
  }

  // ─────────────────────────────────────────────────────────
  // SCENE 9: Final wide shot
  // ─────────────────────────────────────────────────────────
  console.log('📍  Scene 9 — Final pan');
  await page.evaluate(() => window.scrollTo(0, 0));
  await pause(3000);

  // ─────────────────────────────────────────────────────────
  // Done — close context to flush video
  // ─────────────────────────────────────────────────────────
  console.log('\n⏹   Closing browser and flushing video…');
  await context.close();
  await browser.close();

  // Rename the auto-generated webm (playwright uses a uuid filename)
  const files = fs.readdirSync(OUT_DIR).filter(f => f.endsWith('.webm'));
  if (files.length === 0) {
    console.error('No webm file found in demo-out/. Recording may have failed.');
    process.exit(1);
  }
  const rawWebm = path.join(OUT_DIR, files[0]);
  fs.renameSync(rawWebm, WEBM_PATH);
  console.log(`    Saved: ${WEBM_PATH}`);

  // Convert to MP4
  console.log('\n🎞   Converting to MP4 via ffmpeg…');
  const result = spawnSync('ffmpeg', [
    '-y',
    '-i', WEBM_PATH,
    '-c:v', 'libx264',
    '-preset', 'fast',
    '-crf', '22',
    '-c:a', 'aac',
    MP4_PATH,
  ], { stdio: 'inherit' });

  if (result.status !== 0) {
    console.error('ffmpeg conversion failed. WebM is still at:', WEBM_PATH);
    process.exit(1);
  }

  console.log(`\n✅  Demo video saved to: ${MP4_PATH}`);
  console.log('    Upload to Loom via loom.com/upload or drag into Loom desktop app.');
})();

